(()=>{const i=[{name:"Novolun\u011Bn\xED",emoji:"\u{1F311}",minAge:0,maxAge:1.85,illumination:0,tags:["Nov\xE9 za\u010D\xE1tky","Z\xE1m\u011Bry","Introspekce","Ticho"],interpretation:"Novolun\u011Bn\xED je kosmick\xFDm resetem. M\u011Bs\xEDc nen\xED na obloze vid\u011Bt \u2013 cel\xE1 jeho plocha je osv\u011Btlena ze strany, kter\xE1 se d\xEDv\xE1 pry\u010D od n\xE1s. Tato tma nen\xED pr\xE1zdnota, ale \xFArodn\xE1 p\u016Fda. Je to nejsiln\u011Bj\u0161\xED moment pro formulov\xE1n\xED z\xE1m\u011Br\u016F, vizualizace a s\xE1zen\xED semen toho, co chcete p\u0159iv\xE9st do sv\u011Bta v pr\u016Fb\u011Bhu nadch\xE1zej\xEDc\xEDho cyklu.",advice:"\u{1F311} Dne\u0161n\xED praxe: Zapi\u0161te si t\u0159i v\u011Bci, kter\xE9 si p\u0159ejete vytvo\u0159it nebo p\u0159it\xE1hnout v p\u0159\xED\u0161t\xEDch 29 dnech. Pak je pus\u0165te \u2013 a sledujte, jak se vesm\xEDr za\u010Dne pohybovat."},{name:"Dor\u016Fstaj\xEDc\xED srpek",emoji:"\u{1F312}",minAge:1.85,maxAge:6.38,illumination:25,tags:["Akce","Iniciativa","V\xEDra","Nad\u0161en\xED"],interpretation:"Tenk\xFD srpek M\u011Bs\xEDce se objevuje na ve\u010Dern\xED obloze jako prvn\xED viditeln\xFD p\u0159\xEDslib. Energie tohoto obdob\xED \u0159\xEDk\xE1: Je \u010Das za\u010D\xEDt jednat na z\xE1klad\u011B z\xE1m\u011Br\u016F, kter\xE9 jste zaseli p\u0159i Novolun\u011Bn\xED. Je\u0161t\u011B pln\xE9 sv\u011Btlo nep\u0159i\u0161lo, ale sm\u011Br je jasn\xFD. Toto nen\xED \u010Das na p\u0159em\xFD\u0161len\xED \u2013 je to \u010Das na prvn\xED kroky.",advice:"\u{1F312} Dne\u0161n\xED praxe: Ud\u011Blejte konkr\xE9tn\xED prvn\xED krok ke sv\xE9mu z\xE1m\u011Bru. Jakkoli mal\xFD. Ka\u017Ed\xFD velk\xFD projekt za\u010D\xEDn\xE1 jednou neohrabanou akc\xED."},{name:"Prvn\xED \u010Dtvr\u0165",emoji:"\u{1F313}",minAge:6.38,maxAge:8,illumination:50,tags:["P\u0159ek\xE1\u017Eky","Rozhodnut\xED","V\u016Fle","Konflikt"],interpretation:"P\u0159esn\u011B polovina M\u011Bs\xEDce je osv\u011Btlena \u2013 symbolick\xE1 rovnov\xE1ha a z\xE1rove\u0148 nap\u011Bt\xED. Toto je bod, kdy se z\xE1m\u011Bry st\u0159et\xE1vaj\xED s realitou. M\u016F\u017Ee p\u0159ij\xEDt prvn\xED vnit\u0159n\xED nebo vn\u011Bj\u0161\xED odpor. Tyto p\u0159ek\xE1\u017Eky nejsou sign\xE1lem k vzd\xE1n\xED se \u2013 jsou zkou\u0161kou, zda chcete sv\u016Fj c\xEDl skute\u010Dn\u011B naplnit.",advice:"\u{1F313} Dne\u0161n\xED praxe: Co v\xE1s brzd\xED? Pojmenujte jednu konkr\xE9tn\xED p\u0159ek\xE1\u017Eku a rozhodn\u011Bte se, jak p\u0159es ni projdete. Rozhodnut\xED je mocn\u011Bj\u0161\xED ne\u017E pl\xE1n."},{name:"Dor\u016Fstaj\xEDc\xED m\u011Bs\xEDc",emoji:"\u{1F314}",minAge:8,maxAge:13.77,illumination:75,tags:["Vytrvalost","Zdokonalov\xE1n\xED","Anal\xFDza","Dola\u010Fov\xE1n\xED"],interpretation:"M\u011Bs\xEDc je t\xE9m\u011B\u0159 pln\xFD a energie nar\u016Fst\xE1 s t\xE9m\u011B\u0159 hmatatelnou intenzitou. Toto je \u010Das pe\u010Dliv\xE9 pr\xE1ce na detailech. Z\xE1m\u011Br je \u017Eiv\xFD, prvn\xED momentum je vytvo\u0159eno \u2013 te\u010F je t\u0159eba vyladit, zdokonalit a vytrvat. P\u0159\xEDprava vrchol\xED.",advice:"\u{1F314} Dne\u0161n\xED praxe: Prostudujte, co funguje a co ne. Prove\u010Fte jednu konkr\xE9tn\xED korekci kurzu. Mistrovstv\xED le\u017E\xED ve vylad\u011Bn\xED drobnost\xED."},{name:"\xDApln\u011Bk",emoji:"\u{1F315}",minAge:13.77,maxAge:15.77,illumination:100,tags:["Vrchol","Manifestace","Emoce","Odhalen\xED","Napln\u011Bn\xED"],interpretation:"\xDApln\u011Bk je esoterickem posv\xE1tn\xFDm momentem lun\xE1rn\xEDho cyklu. M\u011Bs\xEDc je pln\u011B osv\u011Btlen a na obloze z\xE1\u0159\xED jako mal\xE9 druh\xE9 slunce. Emoce jsou zesileny, intuice maxim\xE1ln\u011B naost\u0159ena. To, co bylo zaseto, se nyn\xED pln\u011B projevuje \u2013 dobr\xE9 i \u0161patn\xE9. V\u011Bci se vyno\u0159uj\xED na povrch. Toto je okam\u017Eik sklizn\u011B, ritu\xE1l\u016F vd\u011B\u010Dnosti a propu\u0161t\u011Bn\xED star\xE9ho, co ji\u017E neslou\u017E\xED.",advice:"\u{1F315} Dne\u0161n\xED praxe: Vytvo\u0159te prostor pro ritu\xE1l vd\u011B\u010Dnosti. Napi\u0161te si, co jste od posledn\xEDho Novolun\u011Bn\xED dos\xE1hli, a pot\xE9 v\u011Bdom\u011B propus\u0165te v\u0161e, \u010Deho je t\u0159eba se vzd\xE1t."},{name:"Ub\xFDvaj\xEDc\xED m\u011Bs\xEDc",emoji:"\u{1F316}",minAge:15.77,maxAge:21.15,illumination:75,tags:["Sd\xEDlen\xED","Moudrost","Gratitudine","Odpo\u010Dinek"],interpretation:"Sv\u011Btlo pomalu ustupuje, ale zku\u0161enost a moudrost ze sklizn\u011B \xDApl\u0148ku z\u016Fst\xE1vaj\xED. Toto je \u010Das sd\xEDlen\xED \u2013 toho, co jste se nau\u010Dili, pro\u017Eili a vytvo\u0159ili. Energie p\u0159irozen\u011B vol\xE1 k introverzi, k p\u0159ed\xE1v\xE1n\xED v\u011Bdomost\xED a k ocen\u011Bn\xED cesty.",advice:"\u{1F316} Dne\u0161n\xED praxe: Pod\u011Blte se o n\u011Bco, \u010Demu jste se nau\u010Dili \u2013 a\u0165 u\u017E s p\u0159\xEDtelem, v den\xEDku, nebo na soci\xE1ln\xEDch s\xEDt\xEDch. Moudrost, kter\xE1 nen\xED sd\xEDlena, ch\u0159adne."},{name:"Posledn\xED \u010Dtvr\u0165",emoji:"\u{1F317}",minAge:21.15,maxAge:23.15,illumination:50,tags:["Propu\u0161t\u011Bn\xED","\u010Ci\u0161t\u011Bn\xED","Transformace","P\u0159ehodnocen\xED"],interpretation:"Op\u011Bt polovina \u2013 ale tentokr\xE1t na sestupn\xE9 \u010D\xE1sti cyklu. P\u0159ich\xE1z\xED \u010Das hlubok\xE9ho \xFAklidu: fyzick\xE9ho, emocion\xE1ln\xEDho i ment\xE1ln\xEDho. Co star\xE9ho, p\u0159ebyte\u010Dn\xE9ho nebo ji\u017E nepot\u0159ebn\xE9ho je v m\xE9m \u017Eivot\u011B? Toto je energie propu\u0161t\u011Bn\xED, ne p\u0159id\xE1v\xE1n\xED.",advice:"\u{1F317} Dne\u0161n\xED praxe: Vyho\u010Fte, darujte nebo propus\u0165te jednu v\u011Bc z fyzick\xE9ho prostoru i z mysli. \xDAklid energie vytv\xE1\u0159\xED prostor pro nov\xE9."},{name:"Ub\xFDvaj\xEDc\xED srpek",emoji:"\u{1F318}",minAge:23.15,maxAge:28.5,illumination:15,tags:["Obnova","Odpo\u010Dinek","Ticho","P\u0159\xEDprava"],interpretation:"M\u011Bs\xEDc se vrac\xED k temnot\u011B a cyklus se uzav\xEDr\xE1. Toto je nejintrovertovan\u011Bj\u0161\xED f\xE1ze lun\xE1rn\xEDho cyklu \u2013 \u010Das skute\u010Dn\xE9ho odpo\u010Dinku, regenerace a p\u0159\xEDpravy na nov\xFD za\u010D\xE1tek. Nenutit se do akce. Sp\xE1t v\xEDc. Meditovat. B\xFDt v tichu.",advice:"\u{1F318} Dne\u0161n\xED praxe: Dovolte si dnes odpo\u010Dinout bez v\xFD\u010Ditek. Sp\xE1nek a ticho jsou stejn\u011B produktivn\xED jako akce \u2013 jen jin\xFDm zp\u016Fsobem."}];function r(n){const t=new Date("2026-03-18T04:00:00Z"),e=29.53058867;let o=(n-t)/(1e3*60*60*24)%e;return o<0&&(o+=e),o}function l(n){return i.find(t=>n>=t.minAge&&n<t.maxAge)||i[0]}function m(n){return n.toLocaleDateString("cs-CZ",{weekday:"long",year:"numeric",month:"long",day:"numeric"})}function c(n){const t=document.getElementById("lunarCycleGrid");t.innerHTML=i.map(e=>`
        <div class="cycle-item ${e.name===n.name?"active":""}">
            <span class="cycle-emoji">${e.emoji}</span>
            <div class="cycle-name">${e.name}</div>
        </div>
    `).join("")}function u(n){const e=2*Math.PI*n/29.53058867;return Math.round((1-Math.cos(e))/2*100)}function d(){const n=new Date,t=r(n),e=l(t),a=u(t);document.getElementById("moonEmoji").textContent=e.emoji,document.getElementById("phaseName").textContent=e.name,document.getElementById("phaseDate").textContent=m(n)+` \xB7 V\u011Bk M\u011Bs\xEDce: ${t.toFixed(1)} dn\xED`;const s=Math.round(a/5)*5;document.getElementById("illuminationFill").dataset.illumination=String(s),document.getElementById("illuminationLabel").textContent=`Osv\xEDcen\xED: ${a} %`,document.getElementById("phaseIntroTitle").textContent=`${e.emoji} ${e.name}`,document.getElementById("phaseTags").innerHTML=e.tags.map(o=>`<span class="tag">${o}</span>`).join(""),document.getElementById("phaseInterpretation").textContent=e.interpretation,document.getElementById("phaseAdvice").textContent=e.advice,document.title=`${e.emoji} ${e.name} \u2013 Dne\u0161n\xED Lun\xE1rn\xED F\xE1ze | Mystick\xE1 Hv\u011Bzda`,c(e)}d();})();
